import re, json from typing import Dict from langchain_core.runnables.base import Runnable from langchain.prompts import PromptTemplate from langchain_openai import ChatOpenAI class ConditionalCompressor(Runnable): def __init__(self, threshold=300): self.threshold = threshold self.summarizer = ( PromptTemplate.from_template('80토큰 요약: {docs}') | ChatOpenAI(model='gpt-4o-mini', temperature=0.3) ) def invoke(self, inputs: Dict[str, str]) -&gt; str: docs = inputs['docs']; words = docs.split() if len(words) &gt; self.threshold: sliced = ' '.join(words[:self.threshold]) return self.summarizer.invoke({'docs': sliced}).content return docs # 1) 압축 수행 docs = '

'.join(retrieved_docs) comp_text = ConditionalCompressor().invoke({'docs': docs}) # 2) QA with strict JSON only qa_template = PromptTemplate.from_template( '문서:
{docs}
질문: {question}
' '응답은 오직 JSON 객체 하나({{"answer": "..."}})만 출력하세요.' ) qa = qa_template | ChatOpenAI(model='gpt-4o-mini', temperature=0) qa_msg = qa.invoke({'docs': comp_text, 'question': '공통 주제는 무엇인가요?'}) # 3) 후처리 및 파싱 m = re.search(r"\{.*\}", qa_msg.content, re.S) if not m: raise ValueError('JSON 출력 실패: ' + qa_msg.content) parsed = json.loads(m.group()) print(parsed) . 이 코드 셀은 ‘난이도 상’ 단계로, 조건부 압축과 엄격한 JSON 형식 응답을 구현합니다. 앞서 동적 요약을 활용했지만, 여기서는 텍스트 길이에 따라 요약을 수행할지 말지 결정하고, 모델에게 답변을 JSON 형태로 출력하도록 요구하는 고급 기법을 보여줍니다. 단계별 내용은 다음과 같습니다: . | Python의 기본 모듈 re(정규표현식)와 json을 임포트하고, 타입 힌트를 위해 typing의 Dict를 불러옵니다. 또한 langchain_core.runnables.base에서 Runnable 베이스 클래스를, 그리고 이전에 사용했던 PromptTemplate과 ChatOpenAI를 다시 임포트합니다. Runnable은 Langchain에서 사용자 정의 연산을 체인에 통합하기 위한 기본 클래스입니다. | ConditionalCompressor 라는 커스텀 클래스를 정의합니다. 이 클래스는 Runnable을 상속하여 체인에 넣을 수 있는 조건부 압축기 역할을 합니다: . | 생성자 (__init__): threshold=300이라는 단어 수 임계치를 설정하고, self.summarizer라는 요약 체인을 준비합니다. self.summarizer는 '80토큰 요약: {docs}'라는 요약용 프롬프트 템플릿과 ChatOpenAI(model='gpt-4o-mini', temperature=0.3) 모델을 파이프로 연결한 것으로, 길이가 긴 문서를 최대 80토큰으로 요약하는 역할을 합니다. | invoke 메서드: 입력으로 받은 docs 문자열을 단어별로 나눈 리스트(words)를 만들어 그 길이를 확인합니다. 만약 단어 수가 설정된 임계치(300 단어)보다 많으면, words[:300]으로 앞부분 300단어만 잘라낸 후 이를 self.summarizer.invoke({'docs': sliced})에 전달하여 요약 결과를 얻습니다. 이렇게 요약된 텍스트(.content로 추출)를 반환하고, 반대로 300 단어 이하면 요약을 하지 않고 원문 그대로를 반환합니다. | 이 클래스는 문서가 아주 길 때만 요약을 수행하고 짧으면 그대로 두는 조건부 압축 로직을 캡슐화하고 있습니다. 이를 통해 불필요한 정보 손실을 줄이면서도 입력 길이를 관리할 수 있습니다. | . | 정의한 ConditionalCompressor를 즉시 활용하여 문서 압축을 수행합니다. 먼저 docs = '

'.join(retrieved_docs)로 세 문서를 다시 하나의 문자열로 결합합니다. 그리고 comp_text = ConditionalCompressor().invoke({'docs': docs})를 호출하여 결합된 문서를 조건부 압축기에 넣습니다. 결과로 얻어진 comp_text에는 문서 길이에 따라 압축된 텍스트가 들어갑니다. (현재 예시의 세 문서는 비교적 길기 때문에, 아마도 앞부분 300단어를 요약한 80토큰 분량의 텍스트로 압축되었을 것입니다.) | 압축된 텍스트를 사용하여 질문에 답하는 프롬프트를 구성하고, 모델에게 엄격한 JSON 형식으로 답변을 요구합니다. qa_template 변수를 통해 프롬프트 템플릿을 정의하는데, 여기에는 문서 내용({docs})과 질문({question}) 뿐만 아니라 “응답은 오직 JSON 객체 하나({"answer": "..."})만 출력하세요.” 라는 문장이 포함되어 있습니다. 이 지시는 모델에게 답변을 오로지 {"answer": "..."} 형태의 JSON 한 객체로만 출력하라는 요구사항입니다. 그런 다음 qa_template | ChatOpenAI(model='gpt-4o-mini', temperature=0)로 템플릿과 모델을 파이프로 연결하여 QA 체인을 만들고, qa_msg = qa.invoke({'docs': comp_text, 'question': '공통 주제는 무엇인가요?'})로 실제 질문을 실행합니다. 여기서 질문을 “공통 주제는 무엇인가요?”라고 표현하여 모델이 보다 자연스러운 한국어로 된 질문에 답하도록 했습니다. | 모델의 응답을 받아 후처리 및 파싱을 수행합니다. re.search(r"\{.*\}", qa_msg.content, re.S)를 이용해 모델 출력 문자열에서 {와 }로 둘러싸인 JSON 객체 부분만 찾아냅니다 (re.S 플래그는 줄바꿈이 있어도 전체 문자열에서 패턴을 찾을 수 있도록 합니다). 만약 이러한 JSON 형태를 찾지 못했다면 모델이 지시에 따르지 않고 엉뚱한 형식으로 답변한 것이므로 ValueError를 발생시켜 오류를 표시합니다. JSON 문자열을 올바르게 찾았다면 json.loads(m.group())로 그 문자열을 실제 파이썬 사전(dict) 객체로 변환합니다. 마지막으로 print(parsed)를 통해 파싱된 결과를 출력합니다. 이렇게 하면 모델의 답변이 {'answer': 'AI 기반 교육 기술의 발전과 맞춤형 학습 시스템'}처럼 Python 딕셔너리 형태로 나타나며, 'answer' 키 아래에 세 문서의 공통 주제가 텍스트로 담겨 나오게 됩니다. | .

